SELECT * FROM scheduling
WHERE 1=1
AND deptment_id = #{deptId}
AND employee_id = #{employeeId}
AND schedule_date >= #{startDate}
AND schedule_date <= #{endDate}
ORDER BY schedule_date, noon

SELECT s.*, e.realname as doctorName, e.title_level
FROM scheduling s
         JOIN employee e ON s.employee_id = e.id
WHERE s.deptment_id = #{deptId}
  AND s.schedule_date = #{scheduleDate}
  AND s.noon = #{noon}
  AND s.schedule_status = 'NORMAL'
  AND e.delmark = TRUE
